import{_ as i,c as r,o as a,ag as o}from"./chunks/framework.S-Qvb3wi.js";const c=JSON.parse('{"title":"Dori Find Models（Dori 尋找模型）","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Dori.md","filePath":"zh-TW/Dori.md"}'),t={name:"zh-TW/Dori.md"};function e(n,l,s,u,d,h){return a(),r("div",null,l[0]||(l[0]=[o('<h1 id="dori-find-models-dori-尋找模型" tabindex="-1">Dori Find Models（Dori 尋找模型） <a class="header-anchor" href="#dori-find-models-dori-尋找模型" aria-label="Permalink to &quot;Dori Find Models（Dori 尋找模型）&quot;">​</a></h1><p><strong>Dori Find Models</strong> 是 DGrid 旗下由自然語言驅動的輔助工具，專門用於探索和評估大型語言模型（LLMs）。透過 Dori，您可以用淺顯的中/英文表達需求、使用自有工作負載測試入選的模型，並取得結構化報告，協助您基於數據做出有把握的模型選擇。</p><h2 id="在-dgrid-平台中的角色" tabindex="-1">在 DGrid 平台中的角色 <a class="header-anchor" href="#在-dgrid-平台中的角色" aria-label="Permalink to &quot;在 DGrid 平台中的角色&quot;">​</a></h2><p>Dori 是 DGrid 生態系統中兩項緊密整合的核心功能之一：</p><ul><li><strong>Dori Find Models</strong> – 協助您： <ul><li>將業務或產品需求轉化為具體的模型候選方案</li><li>以引導式、對話式流程探索、測試和比較模型</li></ul></li><li><strong>AI Gateway</strong> – 提供： <ul><li>覆蓋 200 多種生產級 LLMs 的統一抽象層與 API</li><li>基於配置的模型選擇與切換機制，無需修改程式碼</li></ul></li></ul><p>兩者共同實現了端到端的 LLM 工作流程：</p><blockquote><p><strong>傳統方式：</strong> 搜尋供應商 → 建立多個帳戶 → 手動測試 → 針對每個供應商分別整合</p><p><strong>透過 DGrid（Dori + AI Gateway 和 LLM市集）：</strong> 描述需求 → 在單一平臺探索與測試 → 一次性整合 → 透過配置更換模型</p></blockquote><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="_1-自然語言需求蒐集" tabindex="-1">1. 自然語言需求蒐集 <a class="header-anchor" href="#_1-自然語言需求蒐集" aria-label="Permalink to &quot;1. 自然語言需求蒐集&quot;">​</a></h3><p>Dori 從您以自由格式文字記錄的真實業務需求出發。例如：</p><ul><li>「我們需要一款低延遲、高成本效益的模型，用於多語系客服（英文、西班牙文、葡萄牙文），並整合至現有聊天機器人中。」</li><li>「我們正在打造一款專注於 Python 和 TypeScript 的程式碼輔助工具；強大的推理能力與大語境理解能力至關重要。」</li><li>「我們希望獲得針對長文件 RAG 優化的模型，並能在 1 萬以上 token 語境下保持穩定效能。」</li></ul><p>您<strong>無需</strong>瞭解精確的模型名稱、供應商或基準測試縮寫。Dori 會詮釋您的描述，並將其轉化為技術選型標準。</p><h3 id="_2-跨-llm-市集的智慧搜尋" tabindex="-1">2. 跨 LLM 市集的智慧搜尋 <a class="header-anchor" href="#_2-跨-llm-市集的智慧搜尋" aria-label="Permalink to &quot;2. 跨 LLM 市集的智慧搜尋&quot;">​</a></h3><p>蒐集到您的需求後，Dori 會在 <strong>DGrid LLM 市集</strong> 中進行搜尋 —— 該市集透過單一介面彙整了 200 多種 LLMs。</p><p>Dori 具備以下能力：</p><ul><li>依據以下條件過濾候選模型： <ul><li>​<strong>任務適配性</strong>​（例如：聊天、程式碼開發、RAG、多語系支援）</li><li>​<strong>語境視窗</strong>​（短語境 vs 長語境，例如 1 萬以上 tokens）</li><li><strong>延遲與成本配置檔</strong></li><li>其他相關的運營特性</li></ul></li><li>根據您的優先級對模型進行排名： <ul><li>吞吐量與延遲敏感度</li><li>品質與成本的權衡</li><li>特定能力需求（例如：程式開發、推理、多語系支援）</li></ul></li><li>回傳 ​<strong>一份精簡且相關的建議模型清單</strong>​，讓您無需手動瀏覽數十個供應商頁面和基準測試表格。</li></ul><h3 id="_3-統一的真實工作負載測試" tabindex="-1">3. 統一的真實工作負載測試 <a class="header-anchor" href="#_3-統一的真實工作負載測試" aria-label="Permalink to &quot;3. 統一的真實工作負載測試&quot;">​</a></h3><p>在 Dori 提出入選模型清單後，它會協助您在 DGrid 內的 <strong>單一環境</strong> 中測試這些模型：</p><ul><li>直接在平臺上對候選模型執行 <strong>測試驗證</strong></li><li>使用 ​<strong>您自有 Prompt、文件和場景</strong>​，而非泛用範例</li><li>在 <strong>統一、一致的設定</strong> 下評估模型，確保比較結果具有意義</li></ul><p>這消除了常見的作業模式問題：</p><ul><li>各供應商獨立的測試環境</li><li>針對每個 API 編寫的臨時指令碼</li><li>螢幕截圖、筆記和試算表分散在各種工具中</li></ul><h3 id="_4-結構化、可共用的評估" tabindex="-1">4. 結構化、可共用的評估 <a class="header-anchor" href="#_4-結構化、可共用的評估" aria-label="Permalink to &quot;4. 結構化、可共用的評估&quot;">​</a></h3><p>Dori 會生成清晰、結構化的輸出結果，您可與團隊共用並討論，例如：</p><ul><li>每款候選模型的 <strong>範例輸出結果</strong></li><li>有關模型行為與適用性的 <strong>定性筆記</strong></li><li>測試期間觀察到的 <strong>延遲與效能指標</strong></li><li>符合您預期流量模式與負載的 <strong>成本估算</strong></li></ul><p>團隊不再依賴「直覺」和片面資訊，而是能基於可追溯的評估記錄，選擇「最適合我方使用場景的模型」。</p><h3 id="_5-與-ai-閘道的緊密整合" tabindex="-1">5. 與 AI 閘道的緊密整合 <a class="header-anchor" href="#_5-與-ai-閘道的緊密整合" aria-label="Permalink to &quot;5. 與 AI 閘道的緊密整合&quot;">​</a></h3><p>Dori 與 AI 閘道直接聯動，因此您透過 Dori 探索和測試的所有模型，都可立即透過以下方式整合至生產環境：</p><ul><li><strong>一組 API Keys</strong></li><li><strong>一個統一的端點</strong></li><li><strong>一套一致的 API 介面</strong></li></ul><p>核心優勢：</p><ul><li>無需為每個供應商單獨配置身份驗證、SDK 或端點</li><li>透過 Dori 驗證的模型，無需新增供應商整合即可直接使用</li><li>日後更換模型僅需 ​<strong>修改配置</strong>​，無需重新開發專案</li></ul><h2 id="典型使用場景" tabindex="-1">典型使用場景 <a class="header-anchor" href="#典型使用場景" aria-label="Permalink to &quot;典型使用場景&quot;">​</a></h2><h3 id="多語系客服" tabindex="-1">多語系客服 <a class="header-anchor" href="#多語系客服" aria-label="Permalink to &quot;多語系客服&quot;">​</a></h3><ul><li>需求：用於多語系聊天機器人的低延遲、高成本效益 LLM（例如：英文、西班牙文、葡萄牙文）</li><li>Dori 的協助方式： <ul><li>詮釋多語系與延遲需求</li><li>找出適合上述語言的對話式客服模型</li><li>允許您使用真實的客戶查詢和對話流程進行測試</li></ul></li></ul><h3 id="程式碼輔助工具與開發者工具" tabindex="-1">程式碼輔助工具與開發者工具 <a class="header-anchor" href="#程式碼輔助工具與開發者工具" aria-label="Permalink to &quot;程式碼輔助工具與開發者工具&quot;">​</a></h3><ul><li>需求：一款用於 Python、TypeScript 等語言的程式碼生成、解釋與重構模型</li><li>Dori 的協助方式： <ul><li>重點標出具備強大推理與程式開發能力的模型</li><li>強調支援大程式庫的長語境能力</li><li>協助您使用真實程式庫、程式碼片段或任務進行測試驗證</li></ul></li></ul><h3 id="長語境-rag-與文件應用" tabindex="-1">長語境 RAG 與文件應用 <a class="header-anchor" href="#長語境-rag-與文件應用" aria-label="Permalink to &quot;長語境 RAG 與文件應用&quot;">​</a></h3><ul><li>需求：在 1 萬以上 token 語境下，長文件擷取增強生成（RAG）能保持穩定效能</li><li>Dori 的協助方式： <ul><li>依據語境長度與 RAG 適配性過濾模型</li><li>允許您使用實際文件與擷取設定進行評估</li><li>生成報告，記錄大語境下的模型品質與效能表現</li></ul></li></ul><h2 id="不同使用者類型的效益" tabindex="-1">不同使用者類型的效益 <a class="header-anchor" href="#不同使用者類型的效益" aria-label="Permalink to &quot;不同使用者類型的效益&quot;">​</a></h2><h3 id="個人開發者與新創團隊" tabindex="-1">個人開發者與新創團隊 <a class="header-anchor" href="#個人開發者與新創團隊" aria-label="Permalink to &quot;個人開發者與新創團隊&quot;">​</a></h3><ul><li>專注於產品與使用者體驗，而非： <ul><li>鑽研各供應商文件</li><li>整合多個 API 與 SDK</li></ul></li><li>快速迭代： <ul><li>透過 Dori 嘗試多款模型</li><li>透過市集鎖定一款（或多款）模型</li><li>當更優秀的新模型推出時，可隨時更換</li></ul></li></ul><h3 id="企業與大型平臺" tabindex="-1">企業與大型平臺 <a class="header-anchor" href="#企業與大型平臺" aria-label="Permalink to &quot;企業與大型平臺&quot;">​</a></h3><ul><li>透過以下方式標準化跨業務單位的 LLM 存取： <ul><li>與 LLM 市集的單一整合</li><li>透過 Dori 實現共用的評估流程</li></ul></li><li>降低長期維護成本： <ul><li>避免為每個供應商打造自訂化整合方案</li><li>隨著生態系演進，保持採用新模型的彈性</li></ul></li></ul><h3 id="web3-與鏈上專案" tabindex="-1">Web3 與鏈上專案 <a class="header-anchor" href="#web3-與鏈上專案" aria-label="Permalink to &quot;Web3 與鏈上專案&quot;">​</a></h3><ul><li>打造 AI 驅動的代理程式、去中心化應用（dApps）與協議，其模型核心具備以下特性： <ul><li>可隨時間升級</li><li>可跨供應商多元部署</li></ul></li><li>保留鏈上與鏈下整合邏輯，同時： <ul><li>透過配置變更或擴充底層 LLMs</li><li>避免每次採用新模型時出現中斷性變更</li></ul></li></ul>',44)]))}const p=i(t,[["render",e]]);export{c as __pageData,p as default};
